// ══════════════════════════════════════════════════════════════════
// Rogelio — CONIITI 2026 | Lógica principal del asistente
// Variables de entorno requeridas en n8n:
//   OPENAI_API_KEY  → tu API key de OpenAI
//   OPENAI_MODEL    → (opcional) modelo, default: gpt-4o-mini
//   N8N_WEBHOOK_TOKEN → (opcional) token de validación del backend
// ══════════════════════════════════════════════════════════════════

// ── 1. Validar token del backend (si está configurado) ─────────────
const requestHeaders = $input.first().json.headers ?? {};
const bodyRaw = $input.first().json.body ?? $input.first().json;
const expectedToken = $env.N8N_WEBHOOK_TOKEN ?? '';
const receivedToken = requestHeaders['x-coniiti-webhook-token'] ?? '';

if (expectedToken && receivedToken !== expectedToken) {
  return [{ json: { reply: 'No autorizado.' } }];
}

// ── 2. Parsear el payload ──────────────────────────────────────────
const body = typeof bodyRaw === 'string' ? JSON.parse(bodyRaw) : bodyRaw;

const systemPrompt = body?.system_context?.system_prompt
  ?? 'Eres Rogelio, el asistente oficial del Congreso CONIITI 2026 de la Universidad Católica de Colombia. Responde SIEMPRE en español, con tono amable y profesional. Sé conciso: 2-4 frases máximo. Si no sabes algo con certeza, dilo y redirige al panel.';

const rawHistory = Array.isArray(body?.history) ? body.history : [];
const history = rawHistory
  .slice(-10)
  .map(m => ({ role: String(m.role), content: String(m.content ?? '') }))
  .filter(m => m.role === 'user' || m.role === 'assistant');

const userMessage = String(body?.message ?? '').trim();

if (!userMessage) {
  return [{ json: { reply: 'No recibí tu pregunta. Por favor, escribe de nuevo.' } }];
}

// ── 3. Construir array de mensajes para la IA ──────────────────────
const messages = [
  { role: 'system', content: systemPrompt },
  ...history,
  { role: 'user', content: userMessage }
];

// ── 4. Llamar a OpenAI ─────────────────────────────────────────────
const apiKey = $env.OPENAI_API_KEY ?? '';
if (!apiKey) {
  return [{ json: { reply: 'El servicio de IA no está configurado. Contacta al equipo técnico de CONIITI.' } }];
}

const model = $env.OPENAI_MODEL ?? 'gpt-4o-mini';

let reply;
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json',
    },
    body: {
      model,
      messages,
      temperature: 0.3,
      max_tokens: 1200,
      presence_penalty: 0.1,
    },
    json: true,
  });

  reply = response?.choices?.[0]?.message?.content?.trim();
  if (!reply) throw new Error('Respuesta vacía de la IA');

} catch (err) {
  console.error('[Rogelio] Error al llamar a OpenAI:', err.message);
  reply = 'Disculpa, tuve un problema técnico momentáneo. Por favor intenta en unos segundos.';
}

return [{ json: { reply } }];
